from pathlib import Path
path = Path("scripts/smoke_test.ts")
text = path.read_text()
old = """    // Trigger path observation:
    // We observe the IPC push instead of DOM if .joint-cell isn't ready.
    console.log('[SMOKE] Listening for kur:projection-result...');
    const projectionPromise = window.evaluate(() => {
      return new Promise((resolve) => {
        // @ts-ignore
        const unsub = window.KuronodeAPI.onProjectionResult((result) => {
          unsub();
          resolve(result);
        });
        // Timeout guard — pipeline must respond within 30s
        setTimeout(() => resolve({ streamId: 'timeout', _type: 'timeout' }), 30000);
      });
    });

    // Trigger the pipeline via IntentTrigger (Preload API)
    console.log('[SMOKE] Triggering pipeline via intentTrigger...');
    await window.evaluate(() => {
      // @ts-ignore
      window.KuronodeAPI.intentTrigger({ anchors: ['Drone'], scope: 'structural' });
    });

    const result = await projectionPromise;
    console.log('[SMOKE] Received projection result:', (result as any).streamId);

    console.log('[PASS] Headless Pipeline Smoke Test Succeeded.');
"""
new = """    // Trigger path observation:
    // We observe the IPC push instead of DOM if .joint-cell isn't ready.
    type ProjectionResult = { streamId: string; ast?: unknown; _type?: string };
    type KuronodeSmokeApi = {
      onProjectionResult: (handler: (result: unknown) => void) => () => void;
      intentTrigger: (payload: { anchors: string[]; scope: string }) => void;
    };
    const isProjectionResult = (value: unknown): value is ProjectionResult => {
      return typeof value === 'object' && value !== null && typeof (value as { streamId?: unknown }).streamId === 'string';
    };
    const kuronodeApi = (window as Window & { KuronodeAPI?: KuronodeSmokeApi }).KuronodeAPI;
    if (!kuronodeApi) {
      throw new Error('Kuronode preload API missing');
    }

    console.log('[SMOKE] Listening for kur:projection-result...');
    const projectionPromise = window.evaluate(() => {
      return new Promise<unknown>((resolve) => {
        const api = (window as Window & { KuronodeAPI: KuronodeSmokeApi }).KuronodeAPI;
        const unsub = api.onProjectionResult((result: unknown) => {
          unsub();
          resolve(result);
        });
        // Timeout guard — pipeline must respond within 30s
        setTimeout(() => resolve({ streamId: 'timeout', _type: 'timeout' }), 30000);
      });
    });

    // Trigger the pipeline via IntentTrigger (Preload API)
    console.log('[SMOKE] Triggering pipeline via intentTrigger...');
    await window.evaluate(() => {
      const api = (window as Window & { KuronodeAPI: KuronodeSmokeApi }).KuronodeAPI;
      api.intentTrigger({ anchors: ['Drone'], scope: 'structural' });
    });

    const result = await projectionPromise;
    if (!isProjectionResult(result)) {
      throw new Error('Projection result shape invalid');
    }
    if (result.streamId === 'timeout') {
      throw new Error('Projection timed out before kur:projection-result');
    }
    if (!result.ast) {
      throw new Error('Projection result missing ast payload');
    }
    console.log('[SMOKE] Received projection result:', result.streamId);

    console.log('[PASS] Headless Pipeline Smoke Test Succeeded.');
"""
if old not in text:
    raise SystemExit("expected CEB_009 smoke-test fragment not found")
path.write_text(text.replace(old, new))
print("CEB_009 smoke_test.ts patch applied")
